                          <td style={{ padding: '16px', textAlign: 'right', fontFamily: 'JetBrains Mono, monospace', color: '#94a3b8', borderTopRightRadius: '8px', borderBottomRightRadius: '8px' }}>{s.avgOdds.toFixed(2)}</td>
