                        <span style={{ fontSize: '11px', padding: '4px 10px', borderRadius: '6px', background: 'rgba(16,185,129,0.1)', color: '#10b981', fontFamily: 'Inter, sans-serif', fontWeight: '500' }}>{trade.sport}</span>
